  1	import React, { FC, FormEvent, useState } from 'react';
  2	import { useNavigate, useParams } from 'react-router-dom-v5-compat';
  3	
  4	import { NetworkPolicyModel } from '@kubevirt-ui/kubevirt-api/console';
  5	import { IoK8sApiNetworkingV1NetworkPolicy } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
  6	import { k8sCreate, useModal } from '@openshift-console/dynamic-plugin-sdk';
  7	import { Form, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
  8	import ConfirmModal, { ConfirmModalProps } from '@utils/components/ConfirmModal/ConfirmModal';
  9	import { useClusterNetworkFeatures } from '@utils/hooks/useClusterNetworkFeatures';
 10	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 11	import {
 12	  checkNetworkPolicyValidity,
 13	  isNetworkPolicyConversionError,
 14	  NetworkPolicy,
 15	  networkPolicyFromK8sResource,
 16	  networkPolicyNormalizeK8sResource,
 17	  networkPolicyToK8sResource,
 18	} from '@utils/models/index';
 19	import { resourcePathFromModel } from '@utils/resources/shared';
 20	
 21	import NetworkPolicyFormActionButtons from './components/NetworkPolicyFormActionButtons';
 22	import NetworkPolicyFormAlert from './components/NetworkPolicyFormAlert';
 23	import NetworkPolicyFormDenyCheckBoxses from './components/NetworkPolicyFormDenyCheckBoxses';
 24	import NetworkPolicyFormEgress from './components/NetworkPolicyFormEgress';
 25	import NetworkPolicyFormIngress from './components/NetworkPolicyFormIngress';
 26	import NetworkPolicyFormName from './components/NetworkPolicyFormName';
 27	import NetworkPolicyFormPodSelector from './components/NetworkPolicyFormPodSelector';
 28	import NetworkPolicyFormSDNAlert from './components/NetworkPolicyFormSDNAlert';
 29	import useIsMultiNetworkPolicy from './hooks/useIsMultiNetworkPolicy';
 30	import NADsSelector from './NADsSelector';
 31	
 32	type NetworkPolicyFormSectionsProps = {
 33	  formData: IoK8sApiNetworkingV1NetworkPolicy;
 34	  onChange: (newFormData: IoK8sApiNetworkingV1NetworkPolicy) => void;
 35	};
 36	
 37	const NetworkPolicyFormSections: FC<NetworkPolicyFormSectionsProps> = ({ formData, onChange }) => {
 38	  const navigate = useNavigate();
 39	  const { t } = useNetworkingTranslation();
 40	
 41	  const isMultiCreateForm = useIsMultiNetworkPolicy();
 42	  const { ns: namespace } = useParams();
 43	
 44	  const createModal = useModal();
 45	
 46	  const normalizedK8S = networkPolicyNormalizeK8sResource(formData);
 47	  const converted = networkPolicyFromK8sResource(normalizedK8S);
 48	  const [networkPolicy, setNetworkPolicy] = useState(converted);
 49	
 50	  const [inProgress, setInProgress] = useState(false);
 51	  const [error, setError] = useState('');
 52	  const [networkFeatures, networkFeaturesLoaded] = useClusterNetworkFeatures();
 53	
 54	  if (isNetworkPolicyConversionError(networkPolicy)) {
 55	    return (
 56	      <NetworkPolicyFormAlert
 57	        message={networkPolicy.error}
 58	        title={t(
 59	          'This NetworkPolicy cannot be displayed in form. Please switch to the YAML editor.',
 60	        )}
 61	      />
 62	    );
 63	  }
 64	
 65	  const onPolicyChange = (policy: NetworkPolicy) => {
 66	    setNetworkPolicy(policy);
 67	    onChange(networkPolicyToK8sResource(policy));
 68	  };
 69	
 70	  const removeAll = (msg: string, execute: () => void) => {
 71	    createModal<ConfirmModalProps>(ConfirmModal, {
 72	      btnText: t('Remove all'),
 73	      executeFn: () => {
 74	        execute();
 75	        return Promise.resolve();
 76	      },
 77	      message: msg,
 78	      title: t('Are you sure?'),
 79	    });
 80	  };
 81	
 82	  const onSubmit = async (event: FormEvent) => {
 83	    event.preventDefault();
 84	
 85	    const invalid = checkNetworkPolicyValidity(networkPolicy);
 86	    if (invalid) {
 87	      setError(invalid.error);
 88	      return;
 89	    }
 90	    const policy = networkPolicyToK8sResource(networkPolicy);
 91	    try {
 92	      setInProgress(true);
 93	      await k8sCreate({ data: policy, model: NetworkPolicyModel });
 94	      setInProgress(false);
 95	      navigate(
 96	        resourcePathFromModel(NetworkPolicyModel, networkPolicy.name, networkPolicy.namespace),
 97	      );
 98	    } catch (err) {
 99	      setError(err.message);
100	      setInProgress(false);
101	    }
102	  };
103	
104	  return (
105	    <PageSection variant={PageSectionVariants.light}>
106	      <Form className="co-create-networkpolicy" onSubmit={onSubmit}>
107	        <NetworkPolicyFormSDNAlert
108	          networkFeatures={networkFeatures}
109	          networkFeaturesLoaded={networkFeaturesLoaded}
110	        />
111	        <NetworkPolicyFormName networkPolicy={networkPolicy} onPolicyChange={onPolicyChange} />
112	        {isMultiCreateForm && (
113	          <NADsSelector
114	            namespace={namespace}
115	            networkPolicy={networkPolicy}
116	            onPolicyChange={onPolicyChange}
117	          />
118	        )}
119	        <NetworkPolicyFormPodSelector
120	          networkPolicy={networkPolicy}
121	          onPolicyChange={onPolicyChange}
122	        />
123	        <Title headingLevel="h2">{t('Policy type')}</Title>
124	        <NetworkPolicyFormDenyCheckBoxses
125	          networkFeatures={networkFeatures}
126	          networkFeaturesLoaded={networkFeaturesLoaded}
127	          networkPolicy={networkPolicy}
128	          onPolicyChange={onPolicyChange}
129	        />
130	        <NetworkPolicyFormIngress
131	          networkPolicy={networkPolicy}
132	          onPolicyChange={onPolicyChange}
133	          removeAll={removeAll}
134	        />
135	        <NetworkPolicyFormEgress
136	          networkFeatures={networkFeatures}
137	          networkFeaturesLoaded={networkFeaturesLoaded}
138	          networkPolicy={networkPolicy}
139	          onPolicyChange={onPolicyChange}
140	          removeAll={removeAll}
141	        />
142	        {error && <NetworkPolicyFormAlert message={error} title={t('Error')} />}
143	        <NetworkPolicyFormActionButtons isDisabled={inProgress} isLoading={inProgress} />
144	      </Form>
145	    </PageSection>
146	  );
147	};
148	
149	export default NetworkPolicyFormSections;

